blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie zobaczysz, <strong>kiedy dodać by + agent</strong> w stronie biernej, kiedy lepiej pominąć wykonawcę i czym różnią się <strong>by</strong> oraz <strong>with</strong>.",
    "rules": [
        {
            "label": "Dodaj by + agent",
            "color": "emerald",
            "text": "Dodajemy wykonawcę, gdy jest <strong>ważny, nowy albo zaskakujący</strong>.",
            "example": "The book was written by J.K. Rowling."
        },
        {
            "label": "Pomiń wykonawcę",
            "color": "blue",
            "text": "Nie dodajemy <strong>by + agent</strong>, gdy wykonawca jest oczywisty, nieznany albo nieważny.",
            "example": "He was arrested."
        },
        {
            "label": "by vs with",
            "color": "rose",
            "text": "<strong>By</strong> wskazuje wykonawcę, a <strong>with</strong> narzędzie albo środek.",
            "example": "The letter was written by Tom with a pen."
        }
    ]
}

{
    "title": "1. Kiedy DODAĆ „przez + agenta”",
    "sections": [
        {
            "label": "Wykonawca jest ważny",
            "color": "emerald",
            "description": "Jeśli artysta jest <strong>kluczową informacją</strong>, należy ją określić.",
            "examples": [
                {
                    "en": "The Mona Lisa was painted by Leonardo da Vinci.",
                    "ua": "„Mona Lisa” została namalowana przez Leonarda da Vinci."
                },
                {
                    "en": "This song was performed by Adele.",
                    "ua": "Tę piosenkę wykonała Adele."
                },
                {
                    "en": "The company was founded by Steve Jobs.",
                    "ua": "Firmę założył Steve Jobs."
                }
            ]
        },
        {
            "label": "Nowe informacje",
            "color": "sky",
            "description": "Gdy wykonawca jest dla słuchacza <strong>nową, nieoczekiwaną informacją</strong>.",
            "examples": [
                {
                    "en": "I was helped by a stranger.",
                    "ua": "Pomógł mi nieznajomy."
                },
                {
                    "en": "The window was broken by the kids next door.",
                    "ua": "Dzieci sąsiadów wybiły szybę."
                },
                {
                    "en": "The project was completed by our junior team.",
                    "ua": "Projekt zrealizował nasz zespół juniorów."
                }
            ]
        },
        {
            "label": "Kontrast/podkreślenie",
            "color": "amber",
            "description": "Gdy chcemy <strong>podkreślić, kto dokładnie</strong> wykonał czynność.",
            "examples": [
                {
                    "en": "The report was written by me, not by Tom.",
                    "ua": "To ja napisałem raport, nie Tom."
                },
                {
                    "en": "The cake was made by my grandmother.",
                    "ua": "Ciasto upiekła moja babcia. (akcent)"
                }
            ]
        }
    ]
}

{
    "title": "2. Kiedy POMINĄĆ „przez + agenta”",
    "sections": [
        {
            "label": "Wykonawca jest oczywisty",
            "color": "emerald",
            "description": "Kiedy z kontekstu <strong>jasno</strong> wynika, kto wykonuje czynność.",
            "examples": [
                {
                    "en": "He was arrested.",
                    "ua": "Został aresztowany. (policja - oczywiście)"
                },
                {
                    "en": "The patient was operated on.",
                    "ua": "Pacjent był operowany. (lekarze - oczywiście)"
                },
                {
                    "en": "The letter was delivered.",
                    "ua": "Dostarczono listy. (poczta jest oczywista)"
                }
            ]
        },
        {
            "label": "Wykonawca jest nieznany",
            "color": "sky",
            "description": "<strong>Nie wiemy</strong>, kto wykonał tę czynność.",
            "examples": [
                {
                    "en": "My car was stolen.",
                    "ua": "Mój samochód został skradziony. (który jest nieznany)"
                },
                {
                    "en": "The building was constructed in 1920.",
                    "ua": "Budynek wzniesiono w 1920 roku."
                },
                {
                    "en": "The window was broken last night.",
                    "ua": "Wczoraj w nocy wybito okno."
                }
            ]
        },
        {
            "label": "Wykonawca nie jest ważny",
            "color": "amber",
            "description": "<strong>Nie obchodzi nas</strong>, kto wykonuje daną czynność. Ważny wynik.",
            "examples": [
                {
                    "en": "English is spoken here.",
                    "ua": "Mówi się tu po angielsku."
                },
                {
                    "en": "The rules must be followed.",
                    "ua": "Należy przestrzegać zasad."
                },
                {
                    "en": "The work will be finished tomorrow.",
                    "ua": "Prace zakończą się jutro."
                }
            ]
        },
        {
            "label": "Generalny wykonawca",
            "color": "rose",
            "description": "Kiedy wykonawcą są <strong>ludzie w ogóle</strong>: ludzie, ktoś, oni.",
            "examples": [
                {
                    "en": "It is believed that... (people believe)",
                    "ua": "Uważa się, że... (ludzie wierzą)"
                },
                {
                    "en": "The meeting was cancelled.",
                    "ua": "Spotkanie zostało odwołane. (ktoś)"
                }
            ]
        }
    ]
}

{
    "title": "3. „przez” vs „z” — wykonawca vs instrument",
    "sections": [
        {
            "label": "przez",
            "color": "emerald",
            "description": "<strong>przez</strong> wskazuje <strong>wykonawcę</strong> działania (osobę, organizację, siłę).",
            "examples": [
                {
                    "en": "The letter was written by Tom.",
                    "ua": "List został napisany przez Tomka. (wykonawca)"
                },
                {
                    "en": "The house was destroyed by the earthquake.",
                    "ua": "Dom został zniszczony przez trzęsienie ziemi. (moc)"
                },
                {
                    "en": "The decision was made by the committee.",
                    "ua": "Decyzję podjęła komisja. (organizacja)"
                }
            ]
        },
        {
            "label": "z jest narzędziem",
            "color": "blue",
            "description": "<strong>z</strong> wskazuje <strong>narzędzie lub medium</strong>, za pomocą którego wykonywana jest akcja.",
            "examples": [
                {
                    "en": "The letter was written with a pen.",
                    "ua": "List jest napisany ręcznie. (narzędzie)"
                },
                {
                    "en": "The cake was decorated with cream.",
                    "ua": "Tort dekorujemy kremem. (tworzywo)"
                },
                {
                    "en": "The door was locked with a key.",
                    "ua": "Drzwi zamykane są na klucz."
                }
            ]
        },
        {
            "label": "Połączenie przez + z",
            "color": "amber",
            "description": "Możesz użyć <strong>obu</strong> w tym samym zdaniu.",
            "examples": [
                {
                    "en": "The picture was painted by Monet with oil paints.",
                    "ua": "Obraz został namalowany przez Moneta farbami olejnymi."
                },
                {
                    "en": "The document was signed by the manager with a fountain pen.",
                    "ua": "Dokument został podpisany przez kierownika wiecznym piórem."
                }
            ]
        }
    ]
}

{
    "title": "4. Porównanie: przez vs",
    "intro": "Kluczowa różnica między by i with w zdaniach pasywnych to:",
    "rows": [
        {
            "en": "by + agent",
            "ua": "Realizator akcji",
            "note": "The book was written by J.K. Rowling."
        },
        {
            "en": "with + instrument",
            "ua": "Narzędzie, znaczy",
            "note": "The book was written with a pencil."
        },
        {
            "en": "by + natural force",
            "ua": "Siła natury",
            "note": "The tree was struck by lightning."
        },
        {
            "en": "with + material",
            "ua": "Tworzywo",
            "note": "The house was built with bricks."
        }
    ],
    "warning": "📌 <strong>przez</strong> = kto/co spowodowało akcję. <strong>z</strong> = za pomocą którego wykonywana jest akcja."
}

{
    "title": "5. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zbędne by + agent przy oczywistym wykonawcy.",
            "wrong": "He was arrested by police.",
            "right": "✅ He was arrested."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Mylenie by i with.",
            "wrong": "The letter was written with Tom.",
            "right": "✅ The letter was written by Tom."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Użycie by zamiast with przy narzędziu.",
            "wrong": "The cake was cut by a knife.",
            "right": "✅ The cake was cut with a knife."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Niepotrzebne dopowiadanie people / someone.",
            "wrong": "English is spoken by people here.",
            "right": "✅ English is spoken here."
        }
    ]
}
